#include <stdio.h>
#include <string.h>
#include <stdlib.h>

#define MOD 1009419529

long long comb(int n, int k) {
    long long res = 1;
    for (int i = 1; i <= k; i++) {
        res = (res * (n - i + 1)) / i;
    }
    return res;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, k;
        scanf("%d %d", &n, &k);
        char str[n + k + 1];
        scanf("%s", str);
        long long count = comb(n + k, k) - 1;
        printf("%lld\n", count % MOD);
    }
    return 0;
}

